from typing import TypedDict, Annotated
import re
from langgraph.graph import StateGraph

def scan_state_schema_for_pii(state_schema: type[TypedDict]):
    pii_patterns = [
        r'(email|phone|ssn|credit_card|passport)',
        r'(name|address|birthdate)',
        r'(api_key|secret|token)'
    ]

    issues = []
    for field_name, field_type in state_schema.__annotations__.items():
        field_str = str(field_name).lower()
        for pattern in pii_patterns:
            if re.search(pattern, field_str):
                issues.append({
                    'field': field_name,
                    'type': field_type,
                    'risk': 'HIGH'
                })
    return issues

# Usage
class AgentState(TypedDict):
    customer_data: str
    api_keys: dict
    messages: Annotated[list, 'add']

print(scan_state_schema_for_pii(AgentState))

import re
from typing import Any, Dict

from langgraph.checkpoint.sqlite import SqliteSaver

class PIIStateInterceptor:
    def __init__(self):
        self.pii_patterns = [
            r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
            r'\b\d{3}-\d{2}-\d{4}\b',
            r'\b\d{16}\b',
            r'(sk-)[a-zA-Z0-9]{48}'
        ]

    def check_state(self, state: Dict[str, Any]) -> list:
        leaks = []
        for key, value in state.items():
            if isinstance(value, str):
                for pattern in self.pii_patterns:
                    matches = re.finditer(pattern, value)
                    for match in matches:
                        leaks.append({
                            'field': key,
                            'value': match.group(),
                            'location': 'state'
                        })
        return leaks

# Wrap your graph
interceptor = PIIStateInterceptor()
def safe_invoke(graph, input):
    result = graph.invoke(input)
    leaks = interceptor.check_state(result)
    if leaks:
        print('🚨 PII LEAKS DETECTED:', leaks)
    return result

