import sqlite3
import json

def audit_checkpoints(checkpoint_db: str):
    conn = sqlite3.connect(checkpoint_db)
    cursor = conn.cursor()

    cursor.execute('SELECT thread_id, checkpoint FROM checkpoints')
    leaks = []

    for thread_id, checkpoint_json in cursor.fetchall():
        try:
            checkpoint = json.loads(checkpoint_json)
            for key, value in checkpoint.get('config', {}).items():
                if isinstance(value, str) and 'sk-' in value:
                    leaks.append({
                        'thread_id': thread_id,
                        'checkpoint_key': key,
                        'exposed_secret': value[:10] + '...'
                    })
        except:
            pass

    conn.close()
    return leaks

# Usage: audit_checkpoints('checkpoints.sqlite')

