from typing import TypedDict, Annotated
import re
from langgraph.graph import END, StateGraph

class SanitizedState(TypedDict):
    messages: Annotated[list, 'add']
    sanitized_data: dict

PII_REPLACEMENT = '***REDACTED***'

def sanitize_pii_node(state: SanitizedState) -> SanitizedState:
    pii_patterns = [
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
        r'\b\d{3}-\d{2}-\d{4}\b',
        r'(sk-)[a-zA-Z0-9]{48}'
    ]

    sanitized = state['sanitized_data'].copy() if state.get('sanitized_data') else {}

    for key, value in state.items():
        if isinstance(value, str):
            for pattern in pii_patterns:
                value = re.sub(pattern, PII_REPLACEMENT, value)
            sanitized[key] = value

    return {'sanitized_data': sanitized, 'messages': state['messages']}

# Add to your graph
workflow = StateGraph(SanitizedState)
workflow.add_node('sanitize', sanitize_pii_node)
workflow.add_edge('sanitize', 'tools')  # or your next node
workflow.set_entry_point('sanitize')

from typing import TypedDict, Annotated, Any
from langgraph.graph import StateGraph
import hashlib

class SecureAgentState(TypedDict):
    raw_input: str
    sanitized_input: Annotated[str, 'set']
    sensitive_fields: dict[str, str]  # hashed values only
    messages: Annotated[list, 'add']

class SecureStateReducer:
    @staticmethod
    def hash_sensitive(value: str) -> str:
        return hashlib.sha256(value.encode()).hexdigest()[:16]

    @staticmethod
    def sanitize_state(state: SecureAgentState) -> SecureAgentState:
        return {
            **state,
            'sanitized_input': re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL]', state['raw_input']),
            'sensitive_fields': {
                k: SecureStateReducer.hash_sensitive(v) 
                for k, v in state.get('sensitive_fields', {}).items()
            }
        }

# Usage in graph
workflow.add_node('secure_state', SecureStateReducer.sanitize_state)

